const encodedRanges =
  "";

const decodeRanges = (): Uint32Array => {
  const encodedBytes = atob(encodedRanges);
  const ranges = new Uint32Array(encodedBytes.length / 4);

  for (let index = 0; index < ranges.length; index += 1) {
    const byteIndex = index * 4;
    ranges[index] =
      (encodedBytes.charCodeAt(byteIndex) << 24) |
      (encodedBytes.charCodeAt(byteIndex + 1) << 16) |
      (encodedBytes.charCodeAt(byteIndex + 2) << 8) |
      encodedBytes.charCodeAt(byteIndex + 3);
  }

  return ranges;
};

const codePointRanges = decodeRanges();

export const isKleeOneSupportedCharacter = (character: string): boolean => {
  const codePoint = character.codePointAt(0);
  if (codePoint === undefined) {
    return false;
  }

  let low = 0;
  let high = codePointRanges.length / 2 - 1;

  while (low <= high) {
    const middle = Math.floor((low + high) / 2);
    const rangeStart = codePointRanges[middle * 2];
    const rangeEnd = codePointRanges[middle * 2 + 1];

    if (codePoint < rangeStart) {
      high = middle - 1;
    } else if (codePoint > rangeEnd) {
      low = middle + 1;
    } else {
      return true;
    }
  }

  return false;
};
